void test_CB_66_0000()
{
    if (skip_test_CB_66_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();
    auto mmapResult = mmap.Initialize(MinRomBankCount, MinVramBankCount, 1, MinWramBankCount);
    TEST_ASSERT_(mmapResult.IsSuccess(), "%s", mmapResult.GetStatusDescription());

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0xEF25);
    WriteRegisterWord(RegisterType::SP, 0x9B3C);
    WriteRegisterByte(RegisterType::A, 0xB5);
    WriteRegisterByte(RegisterType::B, 0xF6);
    WriteRegisterByte(RegisterType::C, 0xBA);
    WriteRegisterByte(RegisterType::D, 0x0C);
    WriteRegisterByte(RegisterType::E, 0xA1);
    WriteRegisterFlag(0x40);
    WriteRegisterByte(RegisterType::H, 0x9B);
    WriteRegisterByte(RegisterType::L, 0x24);
    mmap.DisableIME();
    WriteRegisterByte(RegisterType::IE, 0x00);
    WriteMemory(0xEF26, 0x66);
    WriteMemory(0xEF25, 0xCB);
    WriteMemory(0x9B24, 0xF3);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 12);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0xB5);
    CheckRegisterByte(RegisterType::B, 0xF6);
    CheckRegisterByte(RegisterType::C, 0xBA);
    CheckRegisterByte(RegisterType::D, 0x0C);
    CheckRegisterByte(RegisterType::E, 0xA1);
    CheckRegisterFlag(0x20);
    CheckRegisterByte(RegisterType::H, 0x9B);
    CheckRegisterByte(RegisterType::L, 0x24);
    CheckRegisterWord(RegisterType::PC, 0xEF27);
    CheckRegisterWord(RegisterType::SP, 0x9B3C);
    TEST_ASSERT(!mmap.IMEEnabled());
    CheckMemory(0x9B24, 0xF3);
    CheckMemory(0xEF25, 0xCB);
    CheckMemory(0xEF26, 0x66);
}

